import React, { useState } from 'react';
import { Plus, Trash2, Settings, X, Scale, Box, Edit2, Check, RotateCcw, Store } from 'lucide-react';
import { Product, UnitType } from '../types';

interface ProductManagerProps {
  products: Product[];
  onAddProduct: (product: Omit<Product, 'id'>) => void;
  onUpdateProduct: (id: string, product: Partial<Product>) => void;
  onDeleteProduct: (id: string) => void;
  isOpen: boolean;
  onClose: () => void;
}

export const ProductManager: React.FC<ProductManagerProps> = ({ 
  products, 
  onAddProduct, 
  onUpdateProduct,
  onDeleteProduct,
  isOpen,
  onClose
}) => {
  const [name, setName] = useState('');
  const [price, setPrice] = useState('');
  const [wholesalePrice, setWholesalePrice] = useState('');
  const [costPrice, setCostPrice] = useState('');
  const [unitType, setUnitType] = useState<UnitType>('piece');

  const [editingId, setEditingId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState({ name: '', price: '', wholesalePrice: '', costPrice: '', unitType: 'piece' as UnitType });

  const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name || !price || !costPrice || !wholesalePrice) return;

    onAddProduct({
      name,
      price: parseFloat(price),
      wholesalePrice: parseFloat(wholesalePrice),
      costPrice: parseFloat(costPrice),
      unitType
    });

    setName('');
    setPrice('');
    setWholesalePrice('');
    setCostPrice('');
    setUnitType('piece');
  };

  const startEdit = (p: Product) => {
    setEditingId(p.id);
    setEditForm({ 
      name: p.name, 
      price: p.price.toString(), 
      wholesalePrice: (p.wholesalePrice || p.price).toString(), 
      costPrice: p.costPrice.toString(), 
      unitType: p.unitType 
    });
  };

  const handleUpdate = () => {
    if (!editingId) return;
    onUpdateProduct(editingId, {
      name: editForm.name,
      price: parseFloat(editForm.price),
      wholesalePrice: parseFloat(editForm.wholesalePrice),
      costPrice: parseFloat(editForm.costPrice),
      unitType: editForm.unitType
    });
    setEditingId(null);
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-gray-800 rounded-2xl w-full max-w-xl shadow-2xl border border-gray-700 animate-fade-up flex flex-col max-h-[85vh]">

        <div className="p-4 border-b border-gray-700 flex justify-between items-center bg-gray-900/50 rounded-t-2xl">
          <div className="flex items-center gap-2 text-white">
            <Settings size={20} className="text-[#FA8072]" />
            <h3 className="font-bold text-lg">إدارة المواد (التسعير والتكلفة)</h3>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-gray-700 rounded-full transition-colors">
            <X size={20} className="text-gray-400" />
          </button>
        </div>

        <div className="p-6 overflow-y-auto">
          {!editingId && (
              <form onSubmit={handleSubmit} className="mb-6 bg-gray-700/30 p-4 rounded-xl border border-gray-600">
                <h4 className="text-sm font-bold text-gray-300 mb-3">إضافة مادة جديدة</h4>
                <div className="flex flex-col gap-3">
                    <input
                        type="text"
                        value={name}
                        onChange={(e) => setName(e.target.value)}
                        placeholder="اسم المادة..."
                        className="w-full px-3 py-2 bg-gray-900 border border-gray-600 text-white rounded-lg outline-none text-sm"
                        required
                    />

                    <div className="grid grid-cols-1 md:grid-cols-3 gap-2">
                        <div className="space-y-1">
                            <label className="text-[10px] text-gray-500 font-bold pr-1">التكلفة</label>
                            <input
                                type="number"
                                value={costPrice}
                                onChange={(e) => setCostPrice(e.target.value)}
                                placeholder="التكلفة"
                                className="w-full px-3 py-2 bg-gray-900 border border-gray-600 text-red-400 rounded-lg outline-none text-sm font-bold"
                                required
                            />
                        </div>
                        <div className="space-y-1">
                            <label className="text-[10px] text-gray-500 font-bold pr-1">سعر المفرق</label>
                            <input
                                type="number"
                                value={price}
                                onChange={(e) => setPrice(e.target.value)}
                                placeholder="سعر المفرق"
                                className="w-full px-3 py-2 bg-gray-900 border border-gray-600 text-green-400 rounded-lg outline-none text-sm font-bold"
                                required
                            />
                        </div>
                        <div className="space-y-1">
                            <label className="text-[10px] text-gray-500 font-bold pr-1">سعر الجملة</label>
                            <input
                                type="number"
                                value={wholesalePrice}
                                onChange={(e) => setWholesalePrice(e.target.value)}
                                placeholder="سعر الجملة"
                                className="w-full px-3 py-2 bg-gray-900 border border-gray-600 text-blue-400 rounded-lg outline-none text-sm font-bold"
                                required
                            />
                        </div>
                    </div>

                    <div className="flex items-center justify-between gap-4">
                        <div className="flex bg-gray-900 rounded-lg p-1 border border-gray-600 shrink-0">
                            <button type="button" onClick={() => setUnitType('piece')} className={`px-3 py-1.5 rounded-md text-xs transition-colors ${unitType === 'piece' ? 'bg-[#FA8072] text-white font-bold' : 'text-gray-400'}`}>قطعة</button>
                            <button type="button" onClick={() => setUnitType('kg')} className={`px-3 py-1.5 rounded-md text-xs transition-colors ${unitType === 'kg' ? 'bg-[#FA8072] text-white font-bold' : 'text-gray-400'}`}>كيلو</button>
                        </div>
                        <button type="submit" className="flex-grow bg-[#FA8072] text-white py-2.5 rounded-lg font-bold flex items-center justify-center gap-2 shadow-lg"><Plus size={18} /> إضافة</button>
                    </div>
                </div>
              </form>
          )}

          {editingId && (
              <div className="mb-6 bg-blue-900/20 p-4 rounded-xl border border-blue-500/30 animate-fade-up">
                  <h4 className="text-sm font-bold text-blue-400 mb-3 flex items-center gap-2"><Edit2 size={16} /> تعديل بيانات: {editForm.name}</h4>
                  <div className="space-y-3">
                      <input type="text" value={editForm.name} onChange={e => setEditForm({...editForm, name: e.target.value})} className="w-full bg-gray-900 border border-gray-600 text-white p-2 rounded-lg text-sm" />
                      <div className="grid grid-cols-1 md:grid-cols-3 gap-2">
                          <div className="space-y-1">
                              <label className="text-[10px] text-gray-400">التكلفة</label>
                              <input type="number" value={editForm.costPrice} onChange={e => setEditForm({...editForm, costPrice: e.target.value})} className="w-full bg-gray-900 border border-gray-600 text-[#FA8072] p-2 rounded-lg font-bold" />
                          </div>
                          <div className="space-y-1">
                              <label className="text-[10px] text-gray-400">المفرق</label>
                              <input type="number" value={editForm.price} onChange={e => setEditForm({...editForm, price: e.target.value})} className="w-full bg-gray-900 border border-gray-600 text-green-400 p-2 rounded-lg font-bold" />
                          </div>
                          <div className="space-y-1">
                              <label className="text-[10px] text-gray-400">الجملة</label>
                              <input type="number" value={editForm.wholesalePrice} onChange={e => setEditForm({...editForm, wholesalePrice: e.target.value})} className="w-full bg-gray-900 border border-gray-600 text-blue-400 p-2 rounded-lg font-bold" />
                          </div>
                      </div>
                      <div className="flex gap-2">
                          <button onClick={handleUpdate} className="flex-1 bg-green-600 text-white py-2 rounded-lg font-bold flex items-center justify-center gap-2"><Check size={18} /> حفظ التغييرات</button>
                          <button onClick={() => setEditingId(null)} className="px-4 bg-gray-700 text-gray-300 py-2 rounded-lg"><RotateCcw size={18} /></button>
                      </div>
                  </div>
              </div>
          )}

          <div className="space-y-2">
            <h4 className="text-sm font-bold text-gray-400 mb-2">قائمة المنتجات ({products.length})</h4>
            <div className="grid gap-2">
                {products.map(product => (
                  <div key={product.id} className="flex justify-between items-center bg-gray-700 p-3 rounded-xl border border-gray-600 group">
                    <div className="flex-grow">
                      <div className="flex items-center gap-2">
                          <span className="text-white font-bold">{product.name}</span>
                          <span className={`text-[9px] px-1.5 py-0.5 rounded text-black font-bold ${product.unitType === 'kg' ? 'bg-yellow-400' : 'bg-blue-300'}`}>{product.unitType === 'kg' ? 'كغ' : 'قطعة'}</span>
                      </div>
                      <div className="flex items-center gap-3 mt-1.5">
                          <div className="flex flex-col"><span className="text-[9px] text-gray-500 uppercase">التكلفة:</span><span className="text-red-400 text-xs font-bold">{product.costPrice.toLocaleString()}</span></div>
                          <div className="flex flex-col"><span className="text-[9px] text-gray-500 uppercase">المفرق:</span><span className="text-green-400 text-xs font-bold">{product.price.toLocaleString()}</span></div>
                          <div className="flex flex-col"><span className="text-[9px] text-gray-500 uppercase">الجملة:</span><span className="text-blue-400 text-xs font-bold">{(product.wholesalePrice || product.price).toLocaleString()}</span></div>
                      </div>
                    </div>

                    <div className="flex items-center gap-1">
                        <button onClick={() => startEdit(product)} className="text-gray-400 hover:text-blue-400 p-2"><Edit2 size={18} /></button>
                        {confirmDeleteId === product.id ? (
                            <div className="flex items-center gap-1">
                                <button onClick={() => { onDeleteProduct(product.id); setConfirmDeleteId(null); }} className="bg-red-500 text-white px-2 py-1 rounded text-xs">تأكيد</button>
                                <button onClick={() => setConfirmDeleteId(null)} className="text-gray-400 text-xs">إلغاء</button>
                            </div>
                        ) : (
                            <button onClick={() => setConfirmDeleteId(product.id)} className="text-gray-500 hover:text-red-400 p-2"><Trash2 size={18} /></button>
                        )}
                    </div>
                  </div>
                ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { ShoppingCart, Settings, Edit3, Trash2, CheckCircle, Plus, Minus, UserPen, Store, UserPlus, X, BadgeDollarSign } from 'lucide-react';
import { SaleItem, Product, UnitType, SaleType, Customer } from '../types';

interface POSInterfaceProps {
  onCompleteOrder: (items: any[], customerName?: string, customerId?: string, saleType?: SaleType) => void;
  products: Product[];
  customers: Customer[];
  onOpenProductManager: () => void;
  onOpenCustomerManager: () => void;
}

export const POSInterface: React.FC<POSInterfaceProps> = ({ 
    onCompleteOrder, products, customers, onOpenProductManager, onOpenCustomerManager 
}) => {
  const [cart, setCart] = useState<any[]>([]);
  const [saleType, setSaleType] = useState<SaleType>('retail');
  const [selectedCustomerId, setSelectedCustomerId] = useState('');
  const [manualCustomerName, setManualCustomerName] = useState(''); 
  const [showCustomInput, setShowCustomInput] = useState(false);
  const [customForm, setCustomForm] = useState({ name: '', price: '', cost: '', unit: 'piece' as UnitType });

  // Update existing cart prices when saleType changes
  useEffect(() => {
    setCart(prev => prev.map(item => {
      const productDef = products.find(p => p.name === item.name && p.unitType === item.unitType);
      if (productDef) {
        return {
          ...item,
          price: saleType === 'wholesale' ? (productDef.wholesalePrice || productDef.price) : productDef.price
        };
      }
      return item;
    }));
  }, [saleType, products]);

  const addToCart = (p: Product) => {
    setCart(prev => {
      const idx = prev.findIndex(i => i.name === p.name && i.unitType === p.unitType);
      const activePrice = saleType === 'wholesale' ? (p.wholesalePrice || p.price) : p.price;

      if (idx > -1) {
        const next = [...prev];
        next[idx] = { ...next[idx], quantity: next[idx].quantity + 1, price: activePrice };
        return next;
      }
      return [...prev, { 
        tempId: Math.random().toString(36).substr(2,9), 
        name: p.name, 
        price: activePrice, 
        costPrice: p.costPrice || 0, 
        quantity: 1, 
        unitType: p.unitType 
      }];
    });
  };

  const addCustomToCart = () => {
    if (!customForm.name || !customForm.price) return;
    setCart(prev => [...prev, { 
        tempId: Math.random().toString(36).substr(2,9), 
        name: customForm.name, 
        price: parseFloat(customForm.price) || 0, 
        costPrice: parseFloat(customForm.cost) || 0,
        quantity: 1,
        unitType: customForm.unit
    }]);
    setCustomForm({ name: '', price: '', cost: '', unit: 'piece' });
    setShowCustomInput(false);
  };

  const updateQty = (id: string, delta: number) => {
    setCart(prev => prev.map(i => i.tempId === id ? { ...i, quantity: Math.max(0.1, parseFloat((i.quantity + delta * (i.unitType === 'kg' ? 0.1 : 1)).toFixed(2))) } : i));
  };

  const updateByPrice = (id: string, totalAmount: string) => {
    const amount = parseFloat(totalAmount);
    if (isNaN(amount) || amount <= 0) return;

    setCart(prev => prev.map(i => {
      if (i.tempId === id && i.unitType === 'kg') {
        const newQty = parseFloat((amount / i.price).toFixed(3));
        return { ...i, quantity: newQty };
      }
      return i;
    }));
  };

  const isCheckoutDisabled = cart.length === 0 || (saleType === 'wholesale' && !selectedCustomerId);

  const handleCheckout = () => {
    if (isCheckoutDisabled) return;

    const items = cart.map(({ name, price, costPrice, quantity, unitType }) => ({ name, price, costPrice, quantity, unitType }));
    const name = saleType === 'wholesale' ? customers.find(c => c.id === selectedCustomerId)?.name : manualCustomerName;

    onCompleteOrder(items, name, selectedCustomerId || undefined, saleType);

    setCart([]); 
    setManualCustomerName(''); 
    setSelectedCustomerId(''); 
    setSaleType('retail');
  };

  const total = cart.reduce((s, i) => s + (i.price * i.quantity), 0);

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 no-print">
      <div className="lg:col-span-2 space-y-4">
        <div className="flex items-center justify-between bg-gray-800 p-4 rounded-xl border border-gray-700">
             <h2 className="font-bold text-white flex items-center gap-2"><Settings className="text-[#FA8072]" size={20} /> قائمة المنتجات</h2>
             <button onClick={onOpenProductManager} className="text-xs bg-gray-700 hover:bg-gray-600 text-gray-300 px-3 py-1.5 rounded-lg transition-colors">تعديل</button>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
            {products.map(p => (
                <button key={p.id} onClick={() => addToCart(p)} className="flex flex-col items-center justify-center p-4 bg-gray-800 border border-gray-700 hover:bg-gray-700 hover:border-[#FA8072] text-white rounded-2xl transition-all shadow-sm active:scale-95 h-32 relative group">
                    <div className={`absolute top-2 right-2 px-1.5 py-0.5 rounded text-[10px] font-bold ${p.unitType === 'kg' ? 'bg-yellow-400 text-black' : 'bg-blue-300 text-black'}`}>{p.unitType === 'kg' ? 'كغ' : 'قطعة'}</div>
                    <span className="font-bold text-sm text-center mb-1 group-hover:text-[#FA8072]">{p.name}</span>
                    <span className="text-xs text-gray-400 bg-gray-900/50 px-2 py-1 rounded-md">
                      {(saleType === 'wholesale' ? (p.wholesalePrice || p.price) : p.price).toLocaleString()} ل.س
                    </span>
                </button>
            ))}
            <button onClick={() => setShowCustomInput(true)} className="flex flex-col items-center justify-center p-4 bg-gray-800 border border-dashed border-gray-600 hover:bg-gray-700 text-gray-400 rounded-2xl h-32"><Edit3 size={20} className="mb-2" /><span className="text-xs">مادة حرة</span></button>
        </div>

        {showCustomInput && (
            <div className="bg-gray-800 p-4 rounded-xl border border-[#FA8072] animate-fade-up relative">
                <button onClick={() => setShowCustomInput(false)} className="absolute left-3 top-3 text-gray-500 hover:text-white"><X size={18} /></button>
                <h4 className="text-sm font-bold text-white mb-3">إضافة مادة حرة</h4>
                <div className="grid grid-cols-1 md:grid-cols-12 gap-2">
                    <input type="text" value={customForm.name} onChange={e => setCustomForm({...customForm, name: e.target.value})} placeholder="المادة" className="md:col-span-4 bg-gray-900 border border-gray-600 text-white px-3 py-2 rounded-lg text-sm" autoFocus />
                    <input type="number" value={customForm.cost} onChange={e => setCustomForm({...customForm, cost: e.target.value})} placeholder="التكلفة" className="md:col-span-2 bg-gray-900 border border-gray-600 text-red-400 px-3 py-2 rounded-lg text-sm" />
                    <input type="number" value={customForm.price} onChange={e => setCustomForm({...customForm, price: e.target.value})} placeholder="البيع" className="md:col-span-2 bg-gray-900 border border-gray-600 text-green-400 px-3 py-2 rounded-lg text-sm" />
                    <select value={customForm.unit} onChange={e => setCustomForm({...customForm, unit: e.target.value as UnitType})} className="md:col-span-2 bg-gray-900 border border-gray-600 text-white px-2 py-2 rounded-lg text-sm"><option value="piece">قطعة</option><option value="kg">كغ</option></select>
                    <button onClick={addCustomToCart} className="md:col-span-2 bg-[#FA8072] text-white rounded-lg font-bold">إضافة</button>
                </div>
            </div>
        )}
      </div>

      <div className="lg:col-span-1">
        <div className="bg-gray-800 rounded-2xl border border-gray-700 shadow-xl overflow-hidden flex flex-col h-full min-h-[500px]">
            <div className="bg-gray-900/80 p-4 border-b border-gray-700 space-y-3">
                <div className="flex justify-between items-center">
                    <h3 className="font-bold text-white flex items-center gap-2"><ShoppingCart size={20} className="text-[#FA8072]" /> سلة المبيعات</h3>
                    {cart.length > 0 && <button onClick={() => setCart([])} className="text-xs text-red-400 underline">إلغاء</button>}
                </div>
                <div className="grid grid-cols-2 bg-gray-700 p-1 rounded-lg">
                    <button onClick={() => setSaleType('retail')} className={`py-1.5 text-xs font-bold rounded-md transition-colors ${saleType === 'retail' ? 'bg-white text-black' : 'text-gray-400'}`}>مفرق</button>
                    <button onClick={() => setSaleType('wholesale')} className={`py-1.5 text-xs font-bold rounded-md transition-colors ${saleType === 'wholesale' ? 'bg-[#FA8072] text-white' : 'text-gray-400'}`}>جملة</button>
                </div>
                {saleType === 'retail' ? (
                     <input type="text" value={manualCustomerName} onChange={e => setManualCustomerName(e.target.value)} placeholder="الاسم (اختياري)..." className="w-full bg-gray-800 border border-gray-600 text-white text-sm rounded-lg px-3 py-2" />
                ) : (
                    <div className="flex gap-2">
                         <select value={selectedCustomerId} onChange={e => setSelectedCustomerId(e.target.value)} className={`w-full bg-gray-800 border text-white text-sm rounded-lg px-3 py-2 outline-none ${!selectedCustomerId && cart.length > 0 ? 'border-orange-500/50' : 'border-gray-600'}`}>
                            <option value="">اختر العميل...</option>
                            {customers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                         </select>
                        <button onClick={onOpenCustomerManager} className="bg-blue-600 text-white px-3 rounded-lg hover:bg-blue-500 transition-colors"><UserPlus size={18} /></button>
                    </div>
                )}
            </div>

            <div className="flex-grow p-3 overflow-y-auto space-y-2">
                {!cart.length ? (
                    <div className="h-full flex flex-col items-center justify-center text-gray-500 opacity-50"><ShoppingCart size={48} className="mb-2" /><p>سلة المبيعات فارغة</p></div>
                ) : (
                    cart.map(i => (
                        <div key={i.tempId} className="bg-gray-700/50 p-3 rounded-xl flex flex-col gap-2 border border-gray-700 relative">
                            <div className="flex justify-between items-start">
                                <div className="flex flex-col"><span className="text-white font-medium text-sm">{i.name}</span><span className="text-[9px] text-gray-400">سعر الوحدة: {i.price}</span></div>
                                <button onClick={() => setCart(p => p.filter(it => it.tempId !== i.tempId))} className="text-gray-500 hover:text-red-500"><Trash2 size={14} /></button>
                            </div>
                            <div className="flex items-center justify-between">
                                <div className="flex items-center gap-1 bg-gray-900 rounded-lg px-2 py-1">
                                    <button onClick={() => updateQty(i.tempId, -1)} className="text-gray-400"><Minus size={10} /></button>
                                    <span className="text-white text-sm font-bold min-w-[35px] text-center">{i.quantity}</span>
                                    <button onClick={() => updateQty(i.tempId, 1)} className="text-gray-400"><Plus size={10} /></button>
                                </div>

                                <div className="flex items-center gap-1">
                                    {i.unitType === 'kg' ? (
                                        <div className="flex flex-col items-end">
                                            <label className="text-[8px] text-gray-500 font-bold mb-0.5">تغيير بالمبلغ:</label>
                                            <input 
                                                type="number" 
                                                defaultValue={parseFloat((i.price * i.quantity).toFixed(0))}
                                                onBlur={(e) => updateByPrice(i.tempId, e.target.value)}
                                                className="w-20 bg-gray-900 border border-[#FA8072]/40 rounded px-1.5 py-0.5 text-right text-xs text-[#FA8072] font-bold outline-none focus:border-[#FA8072]"
                                            />
                                        </div>
                                    ) : (
                                        <span className="text-[#FA8072] font-bold">{(i.price * i.quantity).toLocaleString()} ل.س</span>
                                    )}
                                </div>
                            </div>
                        </div>
                    ))
                )}
            </div>

            <div className="p-4 bg-gray-900 border-t border-gray-700">
                <div className="flex justify-between items-center mb-4">
                    <span className="text-gray-400 font-bold">المجموع النهائي:</span>
                    <span className="text-2xl font-bold text-white">{total.toLocaleString()} <span className="text-xs text-gray-500">ل.س</span></span>
                </div>

                {saleType === 'wholesale' && !selectedCustomerId && cart.length > 0 && (
                    <p className="text-orange-400 text-[10px] text-center mb-2 font-bold animate-pulse">يجب اختيار عميل لتأكيد البيع بالجملة</p>
                )}

                <button 
                  onClick={handleCheckout} 
                  disabled={isCheckoutDisabled} 
                  className={`w-full py-3.5 rounded-xl font-bold text-lg flex items-center justify-center gap-2 transition-all active:scale-95 ${!isCheckoutDisabled ? 'bg-green-600 text-white hover:bg-green-500 shadow-lg shadow-green-900/20' : 'bg-gray-700 text-gray-500 cursor-not-allowed'}`}
                >
                  <CheckCircle size={24} /> 
                  تأكيد البيع
                </button>
            </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { Trash2, ShoppingBag, Search, User, Download, Store, Edit3, Check, X } from 'lucide-react';
import { SaleItem } from '../types';

interface SalesTableProps {
  items: SaleItem[];
  onDeleteItem: (id: string) => void;
  onDeleteOrder?: (orderId: string) => void;
  onPreviewInvoice: (items: SaleItem[]) => void;
  onUpdateItemPrice?: (itemId: string, newPrice: number) => void; // New prop
}

export const SalesTable: React.FC<SalesTableProps> = ({ items, onDeleteItem, onDeleteOrder, onPreviewInvoice, onUpdateItemPrice }) => {
  const [searchTerm, setSearchTerm] = useState<string>('');

  // State for inline deletion confirmation
  const [confirmItemId, setConfirmItemId] = useState<string | null>(null);
  const [confirmOrderId, setConfirmOrderId] = useState<string | null>(null);

  // State for price editing
  const [editingPriceId, setEditingPriceId] = useState<string | null>(null);
  const [tempPrice, setTempPrice] = useState<string>('');

  // Group items by orderId
  const groupedOrders = useMemo(() => {
    const groups: { [key: string]: SaleItem[] } = {};
    items.forEach(item => {
        const key = item.orderId || `legacy-${item.time}`;
        if (!groups[key]) {
            groups[key] = [];
        }
        groups[key].push(item);
    });

    return Object.values(groups).sort((a, b) => 0).reverse();
  }, [items]);

  // Filter logic for Search
  const filteredOrders = useMemo(() => {
      if (!searchTerm) return groupedOrders;
      const lowerTerm = searchTerm.toLowerCase();
      return groupedOrders.filter(group => {
          const first = group[0];
          const name = first.customerName?.toLowerCase() || '';
          const number = first.customerNumber.toString();
          return name.includes(lowerTerm) || number.includes(lowerTerm);
      });
  }, [groupedOrders, searchTerm]);

  const startEditPrice = (item: SaleItem) => {
    setEditingPriceId(item.id);
    setTempPrice(item.price.toString());
  };

  const savePrice = (itemId: string) => {
    const newPrice = parseFloat(tempPrice);
    if (!isNaN(newPrice) && onUpdateItemPrice) {
        onUpdateItemPrice(itemId, newPrice);
    }
    setEditingPriceId(null);
  };

  if (items.length === 0) {
    return (
      <div className="bg-gray-800 p-8 rounded-2xl shadow-sm border border-gray-700 text-center flex flex-col items-center justify-center min-h-[200px] print:hidden">
        <div className="bg-gray-700 p-4 rounded-full mb-3">
            <ShoppingBag className="text-gray-400 w-8 h-8" />
        </div>
        <p className="text-gray-400 font-medium">لا توجد مبيعات مسجلة اليوم حتى الآن.</p>
      </div>
    );
  }

  return (
    <div className="space-y-4">
        {/* Search Bar */}
        <div className="bg-gray-800 p-4 rounded-xl border border-gray-700 flex flex-col md:flex-row items-center gap-4 no-print">
            <div className="relative w-full md:w-96">
                <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
                <input 
                    type="text"
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    placeholder="بحث عن فاتورة (اسم الزبون أو رقمه)..."
                    className="w-full bg-gray-900 border border-gray-600 text-white rounded-xl pr-10 pl-4 py-2 outline-none focus:border-[#FA8072]"
                />
            </div>

            <div className="text-gray-400 text-xs">
                عدد الفواتير المعروضة: {filteredOrders.length}
            </div>
        </div>

        {/* Orders List */}
        <div className="space-y-4">
            {filteredOrders.map((group, index) => {
                const firstItem = group[0];
                const orderTotal = group.reduce((sum, item) => sum + (item.price * item.quantity), 0);
                const orderId = firstItem.orderId;
                const displayName = firstItem.customerName ? `${firstItem.customerName}` : `زبون رقم ${firstItem.customerNumber || '?'}`;
                const isWholesale = firstItem.saleType === 'wholesale';

                return (
                    <div key={orderId || index} className="bg-gray-800 rounded-2xl border border-gray-700 overflow-hidden animate-fade-up">
                        {/* Order Header */}
                        <div className="bg-gray-900/50 p-4 flex flex-wrap items-center justify-between border-b border-gray-700">
                            <div className="flex items-center gap-4">
                                <div className={`px-3 py-1 rounded-lg font-bold border flex items-center gap-2 ${isWholesale ? 'bg-orange-900/20 text-orange-400 border-orange-500/20' : 'bg-blue-900/20 text-blue-400 border-blue-500/20'}`}>
                                    {isWholesale ? <Store size={16} /> : <User size={16} />}
                                    <span>
                                        {displayName}
                                        {firstItem.customerName && <span className="text-xs opacity-70 mr-2">#{firstItem.customerNumber}</span>}
                                    </span>
                                </div>
                                <span className="text-gray-400 text-sm font-mono">{firstItem.time}</span>
                            </div>

                            <div className="flex items-center gap-4 mt-2 md:mt-0">
                                <div className="text-white font-bold">
                                    <span className="text-gray-400 text-sm font-normal ml-2">الإجمالي:</span>
                                    {orderTotal.toLocaleString('en-US')} ل.س
                                </div>

                                <button 
                                    onClick={() => onPreviewInvoice(group)}
                                    className="flex items-center gap-1 bg-green-600 hover:bg-green-500 text-white px-3 py-1.5 rounded-lg text-xs font-bold transition-colors no-print ml-2"
                                >
                                    <Download size={14} />
                                    تحميل PDF
                                </button>

                                {onDeleteOrder && (
                                    confirmOrderId === orderId ? (
                                        <div className="flex items-center gap-2 no-print">
                                            <button 
                                                onClick={(e) => {
                                                    e.stopPropagation();
                                                    onDeleteOrder(orderId);
                                                    setConfirmOrderId(null);
                                                }}
                                                className="bg-red-500 text-white px-2 py-1 rounded text-xs hover:bg-red-600"
                                            >
                                                نعم
                                            </button>
                                            <button onClick={() => setConfirmOrderId(null)} className="bg-gray-600 text-white px-2 py-1 rounded text-xs">إلغاء</button>
                                        </div>
                                    ) : (
                                        <button onClick={() => setConfirmOrderId(orderId)} className="text-red-400 hover:bg-red-400/10 p-2 rounded-lg transition-colors no-print">
                                            <Trash2 size={18} />
                                        </button>
                                    )
                                )}
                            </div>
                        </div>

                        {/* Order Items Table */}
                        <div className="overflow-x-auto">
                            <table className="w-full text-right">
                                <thead className="bg-gray-700/20 text-xs text-gray-400">
                                    <tr>
                                        <th className="py-2 px-4">المادة</th>
                                        <th className="py-2 px-4 text-center">الكمية</th>
                                        <th className="py-2 px-4">السعر</th>
                                        <th className="py-2 px-4">الإجمالي</th>
                                        <th className="py-2 px-4 w-10"></th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-gray-700/50 text-sm">
                                    {group.map(item => (
                                        <tr key={item.id} className="hover:bg-gray-700/20 transition-colors">
                                            <td className="py-2 px-4 font-medium text-gray-200">{item.name}</td>
                                            <td className="py-2 px-4 text-center">
                                                <span className="bg-gray-700 text-gray-300 px-2 py-0.5 rounded text-xs">
                                                    {item.quantity} {item.unitType === 'kg' ? 'كغ' : 'قطعة'}
                                                </span>
                                            </td>
                                            <td className="py-2 px-4 text-gray-400">
                                                {editingPriceId === item.id ? (
                                                    <div className="flex items-center gap-1">
                                                        <input 
                                                            type="number" 
                                                            value={tempPrice} 
                                                            onChange={e => setTempPrice(e.target.value)} 
                                                            className="w-20 bg-gray-900 border border-[#FA8072] text-white text-xs rounded px-1 py-0.5 outline-none"
                                                            autoFocus
                                                        />
                                                        <button onClick={() => savePrice(item.id)} className="text-green-500"><Check size={14}/></button>
                                                        <button onClick={() => setEditingPriceId(null)} className="text-gray-500"><X size={14}/></button>
                                                    </div>
                                                ) : (
                                                    <div className="flex items-center gap-2 group/price cursor-pointer" onClick={() => startEditPrice(item)}>
                                                        <span>{item.price.toLocaleString('en-US')}</span>
                                                        <Edit3 size={12} className="opacity-0 group-hover/price:opacity-100 transition-opacity text-[#FA8072]" />
                                                    </div>
                                                )}
                                            </td>
                                            <td className="py-2 px-4 text-[#FA8072] font-medium">
                                                {(item.price * item.quantity).toLocaleString('en-US')}
                                            </td>
                                            <td className="py-2 px-4 text-left">
                                                {confirmItemId === item.id ? (
                                                    <div className="flex items-center gap-1">
                                                        <button onClick={() => { onDeleteItem(item.id); setConfirmItemId(null); }} className="text-red-500 text-xs font-bold underline">تأكيد</button>
                                                        <button onClick={() => setConfirmItemId(null)} className="text-gray-400 text-xs">إلغاء</button>
                                                    </div>
                                                ) : (
                                                    <button onClick={() => setConfirmItemId(item.id)} className="text-gray-600 hover:text-red-400 transition-colors">
                                                        <Trash2 size={14} />
                                                    </button>
                                                )}
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>
                );
            })}
        </div>
    </div>
  );
};

import React, { useState, useEffect, Suspense, useCallback } from 'react';
import { Header } from './components/Header';
import { POSInterface } from './components/RecipeGenerator';
import { SalesTable } from './components/Menu';
import { Summary } from './components/InfoBox';
import { Login } from './components/Login';
import { SaleItem, Product, ArchivedDay, SaleType, Customer, PurchaseInvoice, Supplier } from './types';
import { Loader2, AlertTriangle, Lock, X, CheckCircle } from 'lucide-react';

const InvoiceModal = React.lazy(() => import('./components/InvoiceModal').then(m => ({ default: m.InvoiceModal })));
const ProductManager = React.lazy(() => import('./components/ProductManager').then(m => ({ default: m.ProductManager })));
const HistoryModal = React.lazy(() => import('./components/HistoryModal').then(m => ({ default: m.HistoryModal })));
const DataManagementModal = React.lazy(() => import('./components/DataManagementModal').then(m => ({ default: m.DataManagementModal })));
const CustomerManager = React.lazy(() => import('./components/CustomerManager').then(m => ({ default: m.CustomerManager })));
const ExpensesModal = React.lazy(() => import('./components/ExpensesModal').then(m => ({ default: m.ExpensesModal })));

const ModalLoader = () => <div className="fixed inset-0 bg-black/50 z-[60] flex items-center justify-center"><div className="bg-gray-800 p-4 rounded-full border border-gray-700"><Loader2 className="animate-spin text-[#FA8072]" size={32} /></div></div>;

const LoadingScreen = ({ progress, message }: { progress: number, message: string }) => {
    const radius = 70;
    const stroke = 8;
    const normalizedRadius = radius - stroke * 2;
    const circumference = normalizedRadius * 2 * Math.PI;
    const strokeDashoffset = circumference - (progress / 100) * circumference;
    return (
      <div className="fixed inset-0 bg-[#0f172a] z-[100] flex flex-col items-center justify-center p-6 text-center">
        <div className="mb-12"><h1 className="text-3xl font-black text-[#FA8072] mb-1">مخبز كوكيز</h1><p className="text-gray-500 text-xs font-bold uppercase">Optimized Engine</p></div>
        <div className="relative flex items-center justify-center mb-10">
            <svg height={radius * 2} width={radius * 2} className="transform rotate-[-90deg]">
                <circle stroke="#1e293b" strokeWidth={stroke} r={normalizedRadius} cx={radius} cy={radius} fill="transparent" />
                <circle stroke="#FA8072" strokeWidth={stroke} strokeDasharray={`${circumference} ${circumference}`} style={{ strokeDashoffset, transition: 'stroke-dashoffset 0.3s x' }} strokeLinecap="round" r={normalizedRadius} cx={radius} cy={radius} fill="transparent" />
            </svg>
            <div className="absolute text-white font-black text-2xl">{progress}%</div>
        </div>
        <div className="max-w-xs w-full bg-gray-800/50 p-4 rounded-2xl border border-gray-700/50 backdrop-blur-md">
            <div className="flex items-center justify-center gap-2 text-[#FA8072] mb-1"><Loader2 size={14} className="animate-spin" /><span className="text-[10px] font-bold tracking-widest uppercase">Syncing</span></div>
            <p className="text-gray-300 font-bold text-sm leading-relaxed">{message}</p>
        </div>
      </div>
    );
};

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(() => sessionStorage.getItem('isAuth') === 'true');
  const [isAppLoading, setIsAppLoading] = useState(false);
  const [loading, setLoading] = useState({ progress: 0, message: '' });

  const [showResetModal, setShowResetModal] = useState(false);
  const [resetPass, setResetPass] = useState('');
  const [resetError, setResetError] = useState(false);

  const [sales, setSales] = useState<SaleItem[]>(() => JSON.parse(localStorage.getItem('dailySales') || '[]'));
  const [purchaseInvoices, setPurchaseInvoices] = useState<PurchaseInvoice[]>(() => JSON.parse(localStorage.getItem('dailyPurchaseInvoices') || '[]'));
  const [history, setHistory] = useState<ArchivedDay[]>(() => JSON.parse(localStorage.getItem('salesHistory') || '[]'));
  const [products, setProducts] = useState<Product[]>(() => JSON.parse(localStorage.getItem('products') || '[]'));
  const [customers, setCustomers] = useState<Customer[]>(() => JSON.parse(localStorage.getItem('customers') || '[]'));
  const [suppliers, setSuppliers] = useState<Supplier[]>(() => JSON.parse(localStorage.getItem('suppliers') || '[]'));

  const [invoiceItems, setInvoiceItems] = useState<SaleItem[] | null>(null);
  const [modals, setModals] = useState({ products: false, customers: false, history: false, data: false, expenses: false });

  useEffect(() => {
    localStorage.setItem('dailySales', JSON.stringify(sales));
    localStorage.setItem('dailyPurchaseInvoices', JSON.stringify(purchaseInvoices));
    localStorage.setItem('salesHistory', JSON.stringify(history));
    localStorage.setItem('products', JSON.stringify(products));
    localStorage.setItem('customers', JSON.stringify(customers));
    localStorage.setItem('suppliers', JSON.stringify(suppliers));
  }, [sales, purchaseInvoices, history, products, customers, suppliers]);

  // Daily sync current state to history
  useEffect(() => {
    const date = new Date().toLocaleDateString('en-GB');
    setHistory(prev => {
      const idx = prev.findIndex(d => d.date === date);
      const data: ArchivedDay = {
        id: idx !== -1 ? prev[idx].id : Date.now().toString(),
        date, timestamp: idx !== -1 ? prev[idx].timestamp : Date.now(),
        totalRevenue: sales.reduce((s, i) => s + (i.price * i.quantity), 0),
        totalExpenses: purchaseInvoices.reduce((s, i) => s + i.totalAmount, 0),
        totalItems: sales.reduce((s, i) => s + i.quantity, 0),
        items: sales, purchaseInvoices
      };
      if (idx !== -1) { 
          const n = [...prev]; 
          if (JSON.stringify(n[idx].items) === JSON.stringify(sales) && JSON.stringify(n[idx].purchaseInvoices) === JSON.stringify(purchaseInvoices)) return prev;
          n[idx] = data; 
          return n; 
      }
      return [data, ...prev];
    });
  }, [sales, purchaseInvoices]);

  const handleExport = useCallback(() => {
      const data = { 
          version: '1.5', 
          backupDate: new Date().toISOString(),
          sales, purchaseInvoices, history, products, customers, suppliers 
      };
      const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `cookies-bakery-backup-${new Date().toLocaleDateString('en-GB').replace(/\//g, '-')}.json`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(url);
  }, [sales, purchaseInvoices, history, products, customers, suppliers]);

  const handleImport = useCallback((file: File) => {
      const reader = new FileReader();
      reader.onload = (e) => {
          try {
              const data = JSON.parse(e.target?.result as string);
              if (data.sales) setSales(data.sales);
              if (data.purchaseInvoices) setPurchaseInvoices(data.purchaseInvoices);
              if (data.history) setHistory(data.history);
              if (data.products) setProducts(data.products);
              if (data.customers) setCustomers(data.customers);
              if (data.suppliers) setSuppliers(data.suppliers);
              alert('تم استيراد البيانات بنجاح!');
              window.location.reload();
          } catch (err) { alert('خطأ في تنسيق الملف!'); }
      };
      reader.readAsText(file);
  }, []);

  const handleUpdateProduct = useCallback((id: string, updates: Partial<Product>) => {
      setProducts(prevProducts => {
          const productToUpdate = prevProducts.find(p => p.id === id);
          if (!productToUpdate) return prevProducts;

          const oldName = productToUpdate.name;
          const newName = updates.name;

          if (newName && newName !== oldName) {
              setSales(prevSales => prevSales.map(item => 
                  item.name === oldName ? { ...item, name: newName } : item
              ));
              setHistory(prevHistory => prevHistory.map(day => ({
                  ...day,
                  items: day.items.map(item => 
                      item.name === oldName ? { ...item, name: newName } : item
                  )
              })));
          }

          return prevProducts.map(p => p.id === id ? { ...p, ...updates } : p);
      });
  }, []);

  const handleUpdateItemPrice = useCallback((itemId: string, newPrice: number) => {
    setSales(prev => prev.map(item => item.id === itemId ? { ...item, price: newPrice } : item));
  }, []);

  const onUpdateArchivedOrder = useCallback((date: string, orderId: string, updatedItems: SaleItem[]) => {
      const today = new Date().toLocaleDateString('en-GB');
      if (date === today) {
          setSales(prev => {
              const rest = prev.filter(i => i.orderId !== orderId);
              return [...rest, ...updatedItems];
          });
      } else {
          setHistory(prev => prev.map(day => {
              if (day.date !== date) return day;
              const newItems = day.items.filter(i => i.orderId !== orderId).concat(updatedItems);
              return { 
                  ...day, 
                  items: newItems,
                  totalRevenue: newItems.reduce((s, i) => s + (i.price * i.quantity), 0),
                  totalItems: newItems.reduce((s, i) => s + i.quantity, 0)
              };
          }));
      }
  }, []);

  const onUpdateArchivedPurchase = useCallback((date: string, purchaseId: string, updatedInvoice: PurchaseInvoice) => {
      const today = new Date().toLocaleDateString('en-GB');
      if (date === today) {
          setPurchaseInvoices(prev => prev.map(inv => inv.id === purchaseId ? updatedInvoice : inv));
      } else {
          setHistory(prev => prev.map(day => {
              if (day.date !== date) return day;
              const newPurchases = day.purchaseInvoices.map(inv => inv.id === purchaseId ? updatedInvoice : inv);
              return { 
                  ...day, 
                  purchaseInvoices: newPurchases,
                  totalExpenses: newPurchases.reduce((s, i) => s + i.totalAmount, 0)
              };
          }));
      }
  }, []);

  const performFullReset = () => {
    if (resetPass === '1997') {
      localStorage.clear();
      sessionStorage.clear();
      window.location.reload();
    } else {
      setResetError(true);
      setResetPass('');
    }
  };

  const handleLogin = () => {
      setIsAppLoading(true);
      const steps = [{ p: 30, m: 'تحميل البيانات...' }, { p: 70, m: 'مزامنة الأرشيف...' }, { p: 100, m: 'جاهز للعمل...' }];
      let i = 0;
      const interval = setInterval(() => {
          if (i < steps.length) { setLoading({ progress: steps[i].p, message: steps[i].m }); i++; } 
          else { clearInterval(interval); sessionStorage.setItem('isAuth', 'true'); setIsAuthenticated(true); setIsAppLoading(false); }
      }, 400);
  };

  const completeOrder = useCallback((items: any[], name?: string, id?: string, type: SaleType = 'retail') => {
      const orderId = Date.now().toString();
      const time = new Date().toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' });

      const currentCustomerNumbers = sales.map(s => Number(s.customerNumber)).filter(n => !isNaN(n));
      const nextCustomerNumber = currentCustomerNumbers.length > 0 ? Math.max(...currentCustomerNumbers) + 1 : 1;

      const finalItems = items.map(i => ({ 
        ...i, 
        id: Math.random().toString(36).substring(2, 11), 
        orderId, 
        customerNumber: nextCustomerNumber, 
        customerName: name || '', 
        customerId: id || '', 
        saleType: type, 
        time 
      }));

      setSales(prev => [...prev, ...finalItems]);
  }, [sales]);

  if (isAppLoading) return <LoadingScreen progress={loading.progress} message={loading.message} />;
  if (!isAuthenticated) return <Login onLogin={handleLogin} />;

  return (
    <div className="min-h-screen flex flex-col bg-gray-900 print:bg-white">
      <Header 
        onOpenHistory={() => setModals({...modals, history: true})} onOpenDataManagement={() => setModals({...modals, data: true})} onOpenExpenses={() => setModals({...modals, expenses: true})}
        isOnline={navigator.onLine} lastSyncTime={new Date()} onManualSync={() => {}} isSyncing={false}
      />
      <main className="flex-grow container mx-auto px-4 py-6 max-w-5xl">
        <Summary items={sales} onPreview={() => setInvoiceItems(sales)} />
        <POSInterface onCompleteOrder={completeOrder} products={products} customers={customers} onOpenProductManager={() => setModals({...modals, products: true})} onOpenCustomerManager={() => setModals({...modals, customers: true})} />
        <div className="mt-8">
            <SalesTable 
                items={sales} 
                onDeleteItem={id => setSales(s => s.filter(i => i.id !== id))} 
                onDeleteOrder={oid => setSales(s => s.filter(i => i.orderId !== oid))} 
                onPreviewInvoice={setInvoiceItems}
                onUpdateItemPrice={handleUpdateItemPrice}
            />
        </div>
      </main>

      <Suspense fallback={<ModalLoader />}>
        {modals.expenses && <ExpensesModal isOpen={modals.expenses} onClose={() => setModals({...modals, expenses: false})} currentPurchases={purchaseInvoices} archivedHistory={history} onAddInvoice={v => setPurchaseInvoices(p => [...p, v])} onDeleteInvoice={id => setPurchaseInvoices(p => p.filter(v => v.id !== id))} suppliers={suppliers} onAddSupplier={s => setSuppliers(p => [...p, {...s, id: Date.now().toString()}])} onDeleteSupplier={id => setSuppliers(p => p.filter(s => s.id !== id))} onUpdatePurchase={onUpdateArchivedPurchase} />}
        {modals.history && <HistoryModal history={history} onClose={() => setModals({...modals, history: false})} onClearHistory={() => setHistory([])} onPreviewInvoice={setInvoiceItems} onUpdateOrder={onUpdateArchivedOrder} />}
        {modals.products && <ProductManager isOpen={modals.products} onClose={() => setModals({...modals, products: false})} products={products} onAddProduct={p => setProducts(s => [...s, {...p, id: Date.now().toString()}])} onUpdateProduct={handleUpdateProduct} onDeleteProduct={id => setProducts(s => s.filter(p => p.id !== id))} />}
        {modals.customers && <CustomerManager isOpen={modals.customers} onClose={() => setModals({...modals, customers: false})} customers={customers} onAddCustomer={c => setCustomers(s => [...s, {...c, id: Date.now().toString()}])} onDeleteCustomer={id => setCustomers(s => s.filter(c => c.id !== id))} />}
        {modals.data && <DataManagementModal onClose={() => setModals({...modals, data: false})} onExport={handleExport} onImport={handleImport} />}
        {invoiceItems && <InvoiceModal items={invoiceItems} onClose={() => setInvoiceItems(null)} />}
      </Suspense>

      {showResetModal && (
        <div className="fixed inset-0 bg-black/95 backdrop-blur-xl z-[100] flex items-center justify-center p-4">
          <div className="bg-gray-800 border border-red-500/30 w-full max-w-sm p-6 rounded-3xl shadow-2xl animate-fade-up">
            <div className="flex justify-between items-start mb-6">
              <div className="bg-red-500/10 p-3 rounded-xl text-red-500"><AlertTriangle size={32} /></div>
              <button onClick={() => { setShowResetModal(false); setResetPass(''); setResetError(false); }} className="text-gray-500 hover:text-white"><X size={24} /></button>
            </div>
            <h2 className="text-xl font-bold text-white mb-2">تصفير الموقع بالكامل؟</h2>
            <p className="text-gray-400 text-sm mb-6 leading-relaxed">سيؤدي هذا الإجراء إلى حذف جميع الفواتير والمنتجات والأرشيف نهائياً من هذا الجهاز.</p>
            <div className="space-y-4">
              <div className="relative">
                <Lock className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
                <input 
                  type="password" 
                  value={resetPass}
                  onChange={(e) => { setResetPass(e.target.value); setResetError(false); }}
                  placeholder="أدخل كلمة المرور"
                  className={`w-full bg-gray-900 border ${resetError ? 'border-red-500' : 'border-gray-700'} text-white rounded-xl py-3 pr-10 pl-4 text-center outline-none focus:border-red-500 transition-all`}
                  autoFocus
                />
              </div>
              {resetError && <p className="text-red-500 text-xs text-center font-bold">خطأ في كلمة المرور!</p>}
              <button onClick={performFullReset} className="w-full bg-red-600 hover:bg-red-700 text-white font-bold py-3.5 rounded-xl transition-all shadow-lg active:scale-95">تأكيد المسح النهائي</button>
            </div>
          </div>
        </div>
      )}

      <footer className="text-center py-6 text-gray-600 text-[10px] no-print">
          <p onClick={() => setShowResetModal(true)} className="cursor-pointer select-none px-4 py-2 hover:text-gray-400 transition-colors inline-block">v1.5 Optimized</p>
      </footer>
    </div>
  );
};

