                                    {editingPriceId === i.tempId ? (
                                        <div className="flex items-center gap-1 mt-1">
                                            <input 
                                                type="number" 
                                                value={tempPrice} 
                                                onChange={e => setTempPrice(e.target.value)}
                                                onKeyDown={e => { if(e.key === 'Enter') handleSavePrice(i.tempId); if(e.key === 'Escape') setEditingPriceId(null); }}
                                                className="w-20 bg-gray-900 border border-[#FA8072] text-white text-[10px] px-1.5 py-0.5 rounded outline-none"
