                      <button onClick={handleSaveInvoice} className="bg-green-600 hover:bg-green-500 text-white px-6 py-2.5 rounded-xl font-bold flex items-center gap-2 shadow-lg"><FileText size={18} /> حفظ الفاتورة</button>
